(() => {
  const currentContact = $('GHL Buscar p/ Transferir').item.json.contact || {};
  const currentTags = currentContact.tags || [];
  const input = $('Trigger').item.json;

  // Remove "Em Atendimento IA" and "Clara SDR", add "Qualificado" and "Transferido Humano"
  let tags = currentTags.filter(t =>
    t !== 'Em Atendimento IA' && t !== 'Clara SDR'
  );
  tags.push('Qualificado');
  tags.push('Transferido Humano');
  tags = [...new Set(tags)];

  const body = { tags };

  // Add resumo as note if provided
  if (input.resumo) {
    body.companyName = currentContact.companyName || '';
  }

  return JSON.stringify(body);
})()
}}

