parameters.jsCode:
const contact = $('GHL Buscar p/ Transferir').item.json.contact || {};
const tagResult = $('GHL Tags Transferência').item.json;

let oppMoved = false;
try {
  const oppResult = $('GHL Mover Etapa').item.json;
  oppMoved = !!oppResult.opportunity;
} catch(e) {}

return [{ json: {
  resultado: "Lead transferido para atendimento humano com sucesso. Tags atualizadas: 'Qualificado' e 'Transferido Humano' adicionadas. Tag 'Em Atendimento IA' removida." + (oppMoved ? " Oportunidade movida para próxima etapa." : ""),
  contact_id: contact.id,
  sucesso: true
}}];

// Process scheduling: find matching slot and prepare appointment
// IMPORTANT: Trigger only receives { query: "..." } from the AI agent
// The query may be a JSON string with phone, data_preferida, horario_preferido
const triggerRaw = $('Trigger').first().json;

// Booking link fallback (GHL calendar widget)
const BOOKING_LINK = 'https://api.leadconnectorhq.com/widget/booking/afd4NA6ULMKfs8VDlaAs';

// Parse the query - it may be a JSON string or plain text
let params = {};
try {
  if (typeof triggerRaw.query === 'string') {
    params = JSON.parse(triggerRaw.query);
  }
} catch (e) {
  params = { query: triggerRaw.query || '' };
}

// Extract fields from parsed params or direct trigger fields
const phone = params.phone || triggerRaw.phone || '';
const dataPref = params.data_preferida || triggerRaw.data_preferida || '';
const horaPref = params.horario_preferido || triggerRaw.horario_preferido || '';
const nomeContato = params.nome_contato || triggerRaw.nome_contato || '';

// Hardcoded IDs
const calendarId = 'afd4NA6ULMKfs8VDlaAs';
const locationId = 'LImTvhcHSBl9dFiTTZfD';

// Get contact from search
const contactData = $('GHL Buscar p/ Agendar').first().json;
let contactId = null;
if (contactData.contacts && contactData.contacts.length > 0) {
  contactId = contactData.contacts[0].id;
} else if (contactData.contact && contactData.contact.id) {
  contactId = contactData.contact.id;
}

// Parse available slots from GHL
const slotsData = $('GHL Slots Disponíveis').first().json;
const allSlots = [];
for (const [date, dateSlots] of Object.entries(slotsData)) {
  if (date === 'traceId' || date === '_metadata') continue;
  if (dateSlots && dateSlots.slots && Array.isArray(dateSlots.slots)) {
    dateSlots.slots.forEach(s => allSlots.push({ date, time: s }));
  } else if (Array.isArray(dateSlots)) {
    dateSlots.forEach(s => allSlots.push({ date, time: s }));
  }
}

// === FALLBACK: No contact found → send booking link ===
if (!contactId) {
  return [{ json: {
    action: 'fallback_link',
    message: 'Para agendar seu diagnóstico gratuito, é só clicar aqui: ' + BOOKING_LINK,
    link: BOOKING_LINK
  } }];
}

// === FALLBACK: No slots available → send booking link ===
if (allSlots.length === 0) {
  return [{ json: {
    action: 'fallback_link',
    message: 'No momento os horários estão atualizando. Você pode escolher o melhor horário direto aqui: ' + BOOKING_LINK,
    link: BOOKING_LINK
  } }];
}

// Try to find matching slot
let selectedSlot = null;
if (dataPref && horaPref) {
  const prefHour = parseInt(horaPref.split(':')[0]);
  const prefMin = parseInt(horaPref.split(':')[1] || '0');

  const daySlots = allSlots.filter(s => s.date === dataPref || (typeof s.time === 'string' && s.time.startsWith(dataPref)));
  if (daySlots.length > 0) {
    let closest = daySlots[0];
    let minDiff = Infinity;
    for (const s of daySlots) {
      const slotTime = new Date(s.time);
      const slotHours = slotTime.getUTCHours() - 3; // BRT = UTC-3
      const slotMins = slotTime.getUTCMinutes();
      const diff = Math.abs((slotHours * 60 + slotMins) - (prefHour * 60 + prefMin));
      if (diff < minDiff) { minDiff = diff; closest = s; }
    }
    selectedSlot = closest;
  }
} else if (dataPref) {
  const daySlots = allSlots.filter(s => s.date === dataPref);
  if (daySlots.length > 0) selectedSlot = daySlots[0];
}

// If no match, offer available slots
if (!selectedSlot) {
  const topSlots = allSlots.slice(0, 8).map(s => {
    const d = new Date(s.time);
    return d.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo', weekday: 'short', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  });
  return [{ json: {
    action: 'offer_slots',
    contactId,
    message: 'Temos esses horários disponíveis: ' + topSlots.join(' | ') + '. Qual fica melhor para você?',
    slots: topSlots,
    link: BOOKING_LINK
  } }];
}

// Found a slot - prepare appointment creation
const startTime = new Date(selectedSlot.time);
const endTime = new Date(startTime.getTime() + 30 * 60 * 1000); // 30 min

return [{ json: {
  action: 'create_appointment',
  contactId,
  calendarId,
  locationId,
  startTime: startTime.toISOString(),
  endTime: endTime.toISOString(),
  title: 'Diagnóstico - ' + (nomeContato || 'Lead'),
  appointmentStatus: 'confirmed',
  phone,
  nome: nomeContato
} }];

// Format appointment result for AI agent
const input = $input.first().json;

// If it came from appointment creation (GHL API response)
if (input.id || (input.calendarId && input.startTime && !input.action)) {
  const start = new Date(input.startTime || input.start);
  const dataFormatada = start.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo', day: '2-digit', month: '2-digit', year: 'numeric' });
  const horaFormatada = start.toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit' });
  return [{ json: {
    sucesso: true,
    mensagem: 'Agendamento confirmado para ' + dataFormatada + ' às ' + horaFormatada,
    data: dataFormatada,
    hora: horaFormatada
  } }];
}

// If it came from fallback_link (no contact found, no slots, etc.)
if (input.action === 'fallback_link') {
  return [{ json: {
    sucesso: true,
    mensagem: input.message,
    link: input.link
  } }];
}

// If it came from offer_slots
if (input.action === 'offer_slots') {
  return [{ json: {
    sucesso: true,
    mensagem: input.message,
    slots: input.slots || [],
    link: input.link || ''
  } }];
}

// If it came from error or unknown action
return [{ json: {
  sucesso: false,
  mensagem: input.message || 'Nosso consultor vai entrar em contato com você em breve para combinar o melhor horário!'
} }];

// Determine pipeline action: create opp, move stage, or skip
const opps = $('Buscar Opp Qualificar').first().json.opportunities || [];
const contact = $('GHL Buscar p/ Qualificar').first().json.contact || {};
const input = $('Trigger').first().json;

// Parse tags sent by Clara
const rawTags = input.tags || '';
const tags = rawTags.split(',').map(t => t.trim().toLowerCase());

// Pipeline constants
const PIPELINE_ID = 'SdaTWIsioZOKhNrj2ecF';
const LOC_ID = 'LImTvhcHSBl9dFiTTZfD';
const STAGE_NOVO = 'e264f262-b123-424f-b102-e8057f995ddd';
const STAGE_SQL = 'd57e5253-5cc1-43cd-8eac-34b5ddafb8bd';

// Check if Clara marked as qualified
const isQualificado = tags.some(t =>
  t === 'qualificado' ||
  t === 'sql' ||
  t.includes('sales qualified') ||
  t.includes('sql')
);

if (opps.length === 0) {
  // No opportunity exists → CREATE
  const stageId = isQualificado ? STAGE_SQL : STAGE_NOVO;
  return [{ json: {
    action: 'create',
    method: 'POST',
    url: 'https://services.leadconnectorhq.com/opportunities/',
    body: JSON.stringify({
      pipelineId: PIPELINE_ID,
      locationId: LOC_ID,
      name: (contact.contactName || 'Lead') + ' - Clara SDR',
      stageId: stageId,
      contactId: contact.id,
      status: 'open'
    })
  }}];
}

const opp = opps[0];

// Only move forward, never backward
// Novo Lead (pos 0) → Qualificado SQL (pos 1)
if (isQualificado && opp.pipelineStageId === STAGE_NOVO) {
  return [{ json: {
    action: 'move',
    method: 'PUT',
    url: 'https://services.leadconnectorhq.com/opportunities/' + opp.id,
    body: JSON.stringify({ pipelineStageId: STAGE_SQL })
  }}];
}

// No action needed (already at right stage or not yet qualified)
return [{ json: { action: 'none', method: '', url: '', body: '' } }];

// Move or create opportunity at "Diagnóstico Agendado" stage
const opps = $('Buscar Opp Agendar').first().json.opportunities || [];
const procData = $('Processar Agendamento').first().json;
const contactId = procData.contactId;
const contactName = procData.nome || 'Lead';

const PIPELINE_ID = 'SdaTWIsioZOKhNrj2ecF';
const LOC_ID = 'LImTvhcHSBl9dFiTTZfD';
const STAGE_AGENDADO = '8725af03-5c92-40ae-9aa1-911016275dc4';

if (!contactId) {
  // No contact → skip
  return [{ json: { method: 'GET', url: 'https://services.leadconnectorhq.com/calendars/', body: '' } }];
}

if (opps.length === 0) {
  // No opportunity → CREATE at Diagnóstico Agendado
  return [{ json: {
    method: 'POST',
    url: 'https://services.leadconnectorhq.com/opportunities/',
    body: JSON.stringify({
      pipelineId: PIPELINE_ID,
      locationId: LOC_ID,
      name: contactName + ' - Diagnóstico Agendado',
      stageId: STAGE_AGENDADO,
      contactId: contactId,
      status: 'open'
    })
  }}];
}

// Opportunity exists → MOVE to Diagnóstico Agendado
const opp = opps[0];
return [{ json: {
  method: 'PUT',
  url: 'https://services.leadconnectorhq.com/opportunities/' + opp.id,
  body: JSON.stringify({ pipelineStageId: STAGE_AGENDADO })
}}];
